          { id: "s2", title: "cook", instruction: "Combine 150g caster sugar and 45ml water in a saucepan over medium-high heat. Swirl the pan gently without stirring until the mixture turns a deep amber color, reaching approximately 175C/350F. Immediately pour the caramel evenly into the base of the ramekins.", materials: [] },
          { id: "s3", title: "prep", instruction: "In a separate saucepan, combine the whole milk, heavy cream, dried lavender, and orange zest. Bring to a gentle simmer, then remove from heat. Let steep for 15 minutes to infuse the flavors.", materials: [] },
          { id: "s4", title: "prep", instruction: "In a large mixing bowl, gently whisk the whole eggs, egg yolks, 75g caster sugar, and vanilla extract until just combined. Avoid whisking vigorously to prevent incorporating air bubbles.", materials: [] },
          { id: "s5", title: "prep", instruction: "Slowly pour the warm infused milk mixture into the eggs while whisking continuously to temper the eggs without scrambling them.", materials: [] },
          { id: "s6", title: "prep", instruction: "Pass the custard base through a fine mesh strainer into a large measuring jug to remove the lavender, orange zest, and any cooked egg bits.", materials: [] },
          { id: "s7", title: "assemble", instruction: "Pour the strained custard equally into the caramel-lined ramekins. Place the ramekins in the roasting pan and carefully pour boiling water into the pan until it reaches halfway up the sides of the ramekins.", materials: [] },
          { id: "s8", title: "cook", instruction: "Carefully transfer the roasting pan to the oven. Bake at 150C/300F for 35 to 40 minutes, ensuring the custard reaches a safe internal temperature of 74C/165F. The custard is ready when the edges are set but the center still jiggles slightly when tapped.", materials: [] },
          { id: "s9", title: "finish", instruction: "Remove the ramekins from the water bath and let them cool to room temperature. Cover with plastic wrap and chill in the refrigerator for at least 4 hours to fully set and allow the caramel to partially dissolve.", materials: [] },
          { id: "s10", title: "finish", instruction: "To serve, run a thin knife around the edge of each ramekin. Place a dessert plate over the top and swiftly invert. Gently tap the bottom of the ramekin and lift it away to reveal the flan and its caramel sauce.", materials: [] }
