export function getRecipeRegion(recipeId: string): string | undefined {
  return RECIPE_REGION_MAP[recipeId];
}

export function getRecipesForRegion(recipes: Recipe[], regionName: string): Recipe[] {
  return recipes.filter((r) => {
    const mapped = RECIPE_REGION_MAP[r.id];
    return mapped === regionName || r.region === regionName;
  });
}

function resolveRecipeImage(recipe: Recipe): Recipe {
  if (recipe.image.startsWith("http")) return recipe;
  return { ...recipe, image: resolveImageUrl(recipe.image) };
}

export function getCountryById(id: string): Country | undefined {
  const c = COUNTRIES.find((c) => c.id === id);
  if (!c) return undefined;
  return { ...c, recipes: c.recipes.map(resolveRecipeImage) };
}

export function getRecipeById(id: string): Recipe | undefined {
  for (const country of COUNTRIES) {
    const recipe = country.recipes.find((r) => r.id === id);
    if (recipe) return resolveRecipeImage(recipe);
  }
  return undefined;
}

export function getAllRecipes(): Recipe[] {
  return COUNTRIES.flatMap((c) => c.recipes.map(resolveRecipeImage));
}
